const BASE = process.env.REACT_APP_API_BASE || "http://127.0.0.1:8000";

async function postJSON(path, body) {
  const res = await fetch(`${BASE}${path}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(`HTTP ${res.status}: ${text}`);
  }
  return res.json();
}

const iconFromText = (t = "") => {
  const s = t.toLowerCase();
  if (s.includes("thunder")) return "⛈️";
  if (s.includes("heavy") && s.includes("rain")) return "🌧️";
  if (s.includes("rain")) return "🌦️";
  if (s.includes("drizzle")) return "🌦️";
  if (s.includes("snow")) return "❄️";
  if (s.includes("sleet")) return "🌨️";
  if (s.includes("hail")) return "🌨️";
  if (s.includes("overcast")) return "☁️";
  if (s.includes("broken") || s.includes("scattered") || s.includes("cloud")) return "⛅";
  if (s.includes("fog") || s.includes("mist") || s.includes("haze")) return "🌫️";
  return "☀️";
};

function normalizeCurrent(payload) {
  const cur = payload?.weather?.current ?? {};
  const description = cur.weather ?? "—";
  return {
    dt: Math.floor(Date.now() / 1000),
    temp: cur.temp ?? null,
    feels_like: null,
    humidity: null,
    wind_speed: null,
    icon: iconFromText(description),
    description,
    precipitation: cur.precipitation ?? 0,
  };
}

function normalizeHourly(payload) {
  const arr = Array.isArray(payload?.weather?.hourly) ? payload.weather.hourly : [];
  return arr.map((h) => {
    const description = h.weather ?? "—";
    return {
      dt: h.date ?? h.dt ?? Math.floor(Date.now() / 1000),
      temp: h.temp ?? null,
      pop: typeof h.pop === "number" ? Math.max(0, Math.min(1, h.pop)) : 0, // clamp to 0..1
      icon: iconFromText(description),
      description,
      precipitation: h.precipitation ?? 0,
    };
  });
}

function normalizeDaily(payload, limit = 16) {
  const arr = Array.isArray(payload?.weather?.daily) ? payload.weather.daily : [];
  return arr.slice(0, limit).map((d) => {
    const description = d.weather ?? "—";
    const t = d.temp ?? {};
    return {
      dt: d.date ?? d.dt ?? Math.floor(Date.now() / 1000),
      min: t.min ?? null,
      max: t.max ?? null,
      pop: typeof d.pop === "number" ? Math.max(0, Math.min(1, d.pop)) : 0,
      icon: iconFromText(description),
      description,
      precipitation: d.precipitation ?? 0,
    };
  });
}

export async function fetchWeather(location) {
  const payload = await postJSON("/api/weather/current", { location });
  return {
    summary: payload?.summary ?? "",
    current: normalizeCurrent(payload),
    hourly: normalizeHourly(payload),
    daily: normalizeDaily(payload, 16),
    raw: payload,
  };
}
